@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@100;200;300&display=swap');

font-family: 'Montserrat', sans-serif;

.Links a, .Links {
  transition: all 200ms ease-in;
}
.Links a {
  background-color:#302D41;
  padding: 15px;
  border-radius: 5px;
}
.Links a i svg {
  position: relative;
  top: 3px;
  right: 2px;
}
.Links a:hover {
  background-color: #ABE9B3;
  color: #161320;
  transform: scale(1.2, 1.2);
}
.Links a:active {
  transform: scale(0.7, 0.7)
}
.Settings .plane {
  background-color: #171717;
  color: #777aff; 
  transition: all 300ms ease;
}
.Settings .plane .Widget {
  background-color: #171717;
}
.Settings .plane:hover {
  width: 35%;
}
.Settings .plane .Widget .settings textarea {
  background-color: #161320;
  width: 100%;
  height: 500px;
  overflow: scroll;
  border: none;
}
.Settings div select,
.Settings div .primary {
  background-color: #161320;
  border: none;
}
.Settings div h2,
.Settings .plane div h4{
  color: #D9E0EE;
}
.Widgets div .Search input {
  border-bottom: 5px solid #ABE9B3;
  border-radius: 5px;
  color: #777aff;
}

.Overlay{
  background-color: #171717;
  color: #777aff;
}
.Overlay i,
.Overlay a:link {
  color: #777aff;
}


@media (max-width: 1000px) {
  .Links {
    display: flex;
    flex-flow: row wrap;
    flex-basis: 200px
    width: 200px;
  }
}
